1	---------------------------------------------------------------------------------------------------
2	-- Copyright (c) 2024-2025 by Oliver Bruendler
3	-- Authors: Oliver Bruendler
4	----------------------------------------------------------------------------------------------------
5	
6	---------------------------------------------------------------------------------------------------
7	-- Description
8	---------------------------------------------------------------------------------------------------
9	-- This components implements a content addressable memory.
10	--
11	-- Documentation:
12	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_cam.md
13	--
14	-- Note: The link points to the documentation of the latest release. If you
15	--       use an older version, the documentation might not match the code.
16	
17	---------------------------------------------------------------------------------------------------
18	-- Libraries
19	---------------------------------------------------------------------------------------------------
20	library ieee;
21	    use ieee.std_logic_1164.all;
22	    use ieee.numeric_std.all;
23	    use ieee.math_real.all;
24	
25	library work;
26	    use work.olo_base_pkg_math.all;
27	    use work.olo_base_pkg_logic.all;
28	    use work.olo_base_pkg_string.all;
29	
30	---------------------------------------------------------------------------------------------------
31	-- Entity
32	---------------------------------------------------------------------------------------------------
33	entity olo_base_cam is
34	    generic (
35	        -- Basic Configuration
36	        Addresses_g          : positive;
37	        ContentWidth_g       : positive;
38	        RamStyle_g           : string   := "auto";
39	        RamBehavior_g        : string   := "RBW";
40	        RamBlockDepth_g      : positive := 512;
41	        ClearAfterReset_g    : boolean  := true;
42	        -- Read/Write interleaving
43	        ReadPriority_g       : boolean  := true;
44	        StrictOrdering_g     : boolean  := false;
45	        -- Pipelineing
46	        UseAddrOut_g         : boolean  := true;
47	        RegisterInput_g      : boolean  := true;
48	        RegisterMatch_g      : boolean  := true;
49	        FirstBitDecLatency_g : natural  := 1
50	    );
51	    port (
52	        -- Control Signals
53	        Clk                     : in    std_logic;
54	        Rst                     : in    std_logic;
55	
56	        -- CAM read request
57	        Rd_Valid                : in    std_logic;
58	        Rd_Ready                : out   std_logic;
59	        Rd_Content              : in    std_logic_vector(ContentWidth_g-1 downto 0);
60	
61	        -- Cam write
62	        Wr_Valid                : in    std_logic;
63	        Wr_Ready                : out   std_logic;
64	        Wr_Content              : in    std_logic_vector(ContentWidth_g-1 downto 0);
65	        Wr_Addr                 : in    std_logic_vector(log2ceil(Addresses_g)-1 downto 0);
66	        Wr_Write                : in    std_logic;
67	        Wr_Clear                : in    std_logic := '0';
68	        Wr_ClearAll             : in    std_logic := '0';
69	
70	        -- CAM one hot read response
71	        Match_Valid             : out   std_logic;
72	        Match_Match             : out   std_logic_vector(Addresses_g-1 downto 0);
73	
74	        -- CAM binary read response
75	        Addr_Valid              : out   std_logic;
76	        Addr_Found              : out   std_logic;
77	        Addr_Addr               : out   std_logic_vector(log2ceil(Addresses_g)-1 downto 0)
78	    );
79	end entity;
80	
81	---------------------------------------------------------------------------------------------------
82	-- Architecture
83	---------------------------------------------------------------------------------------------------
84	architecture rtl of olo_base_cam is
85	
86	    -- *** Constants ***
87	    constant EntityName_c     : string   := "olo_base_cam";
88	    constant BlockAddrBits_c  : positive := log2ceil(RamBlockDepth_g);
89	    constant BlocksParallel_c : positive := integer(ceil(real(ContentWidth_g) / real(BlockAddrBits_c)));
90	    constant TotalAddrBits_c  : positive := BlocksParallel_c * BlockAddrBits_c;
91	
92	    -- *** Two Process Method ***
93	    type TwoProcess_r is record
94	        -- Stage 0
95	        Content_0         : std_logic_vector(ContentWidth_g - 1 downto 0);
96	        Addr_0            : std_logic_vector(log2ceil(Addresses_g)-1 downto 0);
97	        Write_0           : std_logic;
98	        Clear_0           : std_logic;
99	        ClearAll_0        : std_logic;
100	        Read_0            : std_logic;
101	        -- Stage 1
102	        ContentExtended_1 : std_logic_vector(TotalAddrBits_c - 1 downto 0);
103	        Addr_1            : std_logic_vector(log2ceil(Addresses_g)-1 downto 0);
104	        Write_1           : std_logic;
105	        Clear_1           : std_logic;
106	        ClearAll_1        : std_logic;
107	        Read_1            : std_logic;
108	        -- Stage 2
109	        Match_2           : std_logic_vector(Addresses_g-1 downto 0);
110	        Read_2            : std_logic;
111	        -- Clear after reset
112	        RstClearDone      : std_logic;
113	        RstClearCounter   : unsigned(BlockAddrBits_c-1 downto 0);
114	        RstClearWr        : std_logic;
115	    end record;
116	
117	    signal r, r_next : TwoProcess_r;
118	
119	    -- *** Instantiation Signal Types ***
120	    type RamData_t is array (natural range <>) of std_logic_vector(Addresses_g-1 downto 0);
121	
122	    -- *** Instantiation Signals ***
123	    signal ReadContent_0 : std_logic_vector(ContentWidth_g-1 downto 0);
124	    signal RamRead_1     : RamData_t(0 to BlocksParallel_c-1);
125	    signal RamWrite_1    : RamData_t(0 to BlocksParallel_c-1);
126	    signal WrMem_1       : std_logic;
127	    signal MatchInt      : std_logic_vector(Addresses_g-1 downto 0);
128	    signal MatchValid    : std_logic;
129	
130	begin
131	
132	    -----------------------------------------------------------------------------------------------
133	    -- Assertions
134	    -----------------------------------------------------------------------------------------------
135	    assert isPower2(RamBlockDepth_g)
136	        report errorMessage(EntityName_c, "RamBlockDepth_g must be a power of 2")
137	        severity error;
138	
139	    -----------------------------------------------------------------------------------------------
140	    -- Combinatorial Proccess
141	    -----------------------------------------------------------------------------------------------
142	    p_cob : process (all) is
143	        variable v                        : TwoProcess_r;
144	        variable ClearMask_v, SetMask_v   : std_logic_vector(Addresses_g-1 downto 0);
145	        variable InRdReady_v, InWrReady_v : std_logic;
146	    begin
147	        -- *** Hold variables stable ***
148	        v := r;
149	
150	        -- *** Input Ready Handling ***
151	        if ReadPriority_g then
152	            InRdReady_v := '1';
153	            InWrReady_v := not Rd_Valid;
154	        else
155	            InWrReady_v := '1';
156	            InRdReady_v := not Wr_Valid;
157	        end if;
158	        -- For Write and Rad with strict ordering, wait until write is done
159	        if r.Write_0 = '1' or r.Clear_0 = '1' or r.ClearAll_0 = '1' then
160	            InWrReady_v := '0';
161	            if StrictOrdering_g and compareNoCase(RamBehavior_g, "RBW") then
162	                -- If the ordering is not strict or the ram writes befor read, we camm continue reading immediately
163	                InRdReady_v := '0';
164	            else
165	                -- If ordering is not strict, we can always take a read after a write (because WrReady is low)
166	                InRdReady_v := '1';
167	            end if;
168	        end if;
169	        -- Handle Reset
170	        if Rst = '1' or (ClearAfterReset_g and r.RstClearDone = '0') then
171	            InRdReady_v := '0';
172	            InWrReady_v := '0';
173	        end if;
174	        Rd_Ready <= InRdReady_v;
175	        Wr_Ready <= InWrReady_v;
176	
177	        -- *** Stage 0 ***
178	        v.Addr_0     := Wr_Addr;
179	        v.Write_0    := '0';
180	        v.Clear_0    := '0';
181	        v.Read_0     := '0';
182	        v.ClearAll_0 := '0';
183	        if InWrReady_v = '1' and Wr_Valid = '1' then
184	            v.Content_0  := Wr_Content;
185	            v.Write_0    := Wr_Write;
186	            v.Clear_0    := Wr_Clear;
187	            v.ClearAll_0 := Wr_ClearAll;
188	        elsif InRdReady_v = '1' and Rd_Valid = '1' then
189	            v.Content_0 := Rd_Content;
190	            v.Read_0    := '1';
191	        end if;
192	        if RegisterInput_g then
193	            ReadContent_0 <= r.Content_0;
194	        else
195	            ReadContent_0 <= v.Content_0;
196	        end if;
197	
198	        -- *** Stage 1 ***
199	        if RegisterInput_g then
200	            -- Wait for RAM to respond
201	            v.ContentExtended_1                            := (others => '0');
202	            v.ContentExtended_1(ContentWidth_g-1 downto 0) := r.Content_0;
203	            v.Addr_1                                       := r.Addr_0;
204	            v.Write_1                                      := r.Write_0;
205	            v.Clear_1                                      := r.Clear_0;
206	            v.Read_1                                       := r.Read_0;
207	            v.ClearAll_1                                   := r.ClearAll_0;
208	        else
209	            -- Skip one register state
210	            v.ContentExtended_1                            := (others => '0');
211	            v.ContentExtended_1(ContentWidth_g-1 downto 0) := v.Content_0;
212	            v.Addr_1                                       := v.Addr_0;
213	            v.Write_1                                      := v.Write_0;
214	            v.Clear_1                                      := v.Clear_0;
215	            v.Read_1                                       := v.Read_0;
216	            v.ClearAll_1                                   := v.ClearAll_0;
217	        end if;
218	
219	        -- *** Stage 2 ***
220	        v.Read_2 := r.Read_1;
221	        -- Find one hot matching address
222	        v.Match_2 := RamRead_1(0);
223	
224	        -- Loop over all parallel blocks
225	        for i in 1 to BlocksParallel_c-1 loop
226	            v.Match_2 := v.Match_2 and RamRead_1(i);
227	        end loop;
228	
229	        -- Modify CAM content if required
230	        ClearMask_v := (others => '1');
231	        SetMask_v   := (others => '0');
232	        if r.Write_1 = '1' then
233	            -- Write new CAM entry
234	            SetMask_v(fromUslv(to01(r.Addr_1))) := '1';
235	        end if;
236	        if r.Clear_1 = '1' then
237	            -- Clear single CAM entry
238	            ClearMask_v(fromUslv(to01(r.Addr_1))) := '0';
239	        end if;
240	        if r.ClearAll_1 = '1' then
241	            -- Clear all CAM entries - this overrides the single clear mask
242	            -- Note: ClearAll is somewhat timing suboptimal and shall only be used if this is tolerable
243	            ClearMask_v := not v.Match_2;
244	        end if;
245	
246	        -- loop over all blocks
247	        for i in 0 to BlocksParallel_c-1 loop
248	            RamWrite_1(i) <= (RamRead_1(i) and ClearMask_v) or SetMask_v;
249	        end loop;
250	
251	        WrMem_1 <= r.Write_1 or r.Clear_1 or r.ClearAll_1 or r.RstClearWr;
252	        -- One hot output
253	        if RegisterMatch_g then
254	            MatchValid <= r.Read_2;
255	            MatchInt   <= r.Match_2;
256	        else
257	            MatchValid <= v.Read_2;
258	            MatchInt   <= v.Match_2;
259	        end if;
260	
261	        -- *** Clear after reset ***
262	        v.RstClearWr := '0';
263	        if ClearAfterReset_g then
264	            -- Increment Counter
265	            if r.RstClearDone = '0' then
266	                if r.RstClearCounter = 2**BlockAddrBits_c-1 then
267	                    v.RstClearDone := '1';
268	                else
269	                    v.RstClearCounter := r.RstClearCounter + 1;
270	                end if;
271	            else
272	                v.RstClearDone := '1';
273	            end if;
274	            -- Control clearing signal
275	            if r.RstClearDone = '0' then
276	                -- Deasserting ready signals is done further up where the ready signals are assigned
277	                -- Clear CAM
278	                v.RstClearWr := '1'; -- Assignment to memory write done further up in code
279	
280	                -- loop over all blocks
281	                for i in 0 to BlocksParallel_c-1 loop
282	                    v.ContentExtended_1((i+1)*BlockAddrBits_c-1 downto i*BlockAddrBits_c) := std_logic_vector(r.RstClearCounter);
283	                end loop;
284	
285	            end if;
286	            if r.RstClearWr = '1' then
287	                RamWrite_1 <= (others => (others => '0'));
288	            end if;
289	        end if;
290	
291	        -- *** Assign to signal ***
292	        r_next <= v;
293	    end process;
294	
295	    -- Output signals
296	    Match_Valid <= MatchValid;
297	    Match_Match <= MatchInt;
298	
299	    -----------------------------------------------------------------------------------------------
300	    -- Sequential Proccess
301	    -----------------------------------------------------------------------------------------------
302	    p_seq : process (Clk) is
303	    begin
304	        if rising_edge(Clk) then
305	            r <= r_next;
306	            if Rst = '1' then
307	                r.Write_0         <= '0';
308	                r.Clear_0         <= '0';
309	                r.ClearAll_0      <= '0';
310	                r.Read_0          <= '0';
311	                r.Write_1         <= '0';
312	                r.Clear_1         <= '0';
313	                r.ClearAll_1      <= '0';
314	                r.Read_1          <= '0';
315	                r.Read_2          <= '0';
316	                r.RstClearDone    <= '0';
317	                r.RstClearCounter <= (others => '0');
318	            end if;
319	        end if;
320	    end process;
321	
322	    -----------------------------------------------------------------------------------------------
323	    -- Instantiations
324	    -----------------------------------------------------------------------------------------------
325	    -- CAM memory array
326	    g_addr : for i in 0 to BlocksParallel_c-1 generate
327	        signal ContentExtended_0 : std_logic_vector(TotalAddrBits_c-1 downto 0) := (others => '0');
328	        signal RdAddr_0          : std_logic_vector(BlockAddrBits_c-1 downto 0);
329	        signal WrAddr_1          : std_logic_vector(BlockAddrBits_c-1 downto 0);
330	    begin
331	        -- Input assembly
332	        ContentExtended_0(ContentWidth_g-1 downto 0) <= ReadContent_0;
333	
334	        RdAddr_0 <= to01(ContentExtended_0((i+1)*BlockAddrBits_c-1 downto i*BlockAddrBits_c));
335	        WrAddr_1 <= to01(r.ContentExtended_1((i+1)*BlockAddrBits_c-1 downto i*BlockAddrBits_c));
336	
337	        -- Instance
338	        i_ram : entity work.olo_base_ram_sdp
339	            generic map (
340	                Depth_g         => RamBlockDepth_g,
341	                Width_g         => Addresses_g,
342	                RamStyle_g      => RamStyle_g,
343	                RamBehavior_g   => RamBehavior_g
344	            )
345	            port map (
346	                Clk         => Clk,
347	                Wr_Addr     => WrAddr_1,
348	                Wr_Ena      => WrMem_1,
349	                Wr_Data     => RamWrite_1(i),
350	                Rd_Addr     => RdAddr_0,
351	                Rd_Data     => RamRead_1(i)
352	            );
353	
354	    end generate;
355	
356	    -- First bit decoder
357	    g_addrout : if UseAddrOut_g generate
358	
359	        i_addrout : entity work.olo_base_decode_firstbit
360	            generic map (
361	                InWidth_g       => Addresses_g,
362	                InReg_g         => false,   -- Regiser is in r
363	                OutReg_g        => choose(FirstBitDecLatency_g = 0, false, true),
364	                PlRegs_g        => choose(FirstBitDecLatency_g = 0, 0, FirstBitDecLatency_g-1)
365	            )
366	            port map (
367	                Clk          => Clk,
368	                Rst          => Rst,
369	                In_Data      => MatchInt,
370	                In_Valid     => MatchValid,
371	                Out_FirstBit => Addr_Addr,
372	                Out_Found    => Addr_Found,
373	                Out_Valid    => Addr_Valid
374	            );
375	
376	    end generate;
377	
378	    g_naddrout : if not UseAddrOut_g generate
379	
380	        -- Dummy signals
381	        Addr_Valid <= '0';
382	        Addr_Found <= '0';
383	        Addr_Addr  <= (others => '0');
384	
385	    end generate;
386	
387	end architecture;
388	
