6	---------------------------------------------------------------------------------------------------
7	-- Description
8	---------------------------------------------------------------------------------------------------
9	-- This is a reset generator. It generates a pulse of the specified duration
10	-- after FPGA configuration. The reset output is High-Active according to the
11	-- Open-Logic definitions. The reset generator also allows synchronizing
12	-- asynchronous resets to the output clock domain.
13	--
14	-- Documentation:
15	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_reset_gen.md
16	--
17	-- Note: The link points to the documentation of the latest release. If you
18	--       use an older version, the documentation might not match the code.
19	
20	---------------------------------------------------------------------------------------------------
21	-- Libraries
22	---------------------------------------------------------------------------------------------------
23	library ieee;
24	    use ieee.std_logic_1164.all;
25	    use ieee.numeric_std.all;
26	
27	library work;
28	    use work.olo_base_pkg_math.all;
29	    use work.olo_base_pkg_attribute.all;
30	
31	---------------------------------------------------------------------------------------------------
32	-- Entity
33	---------------------------------------------------------------------------------------------------
34	entity olo_base_reset_gen is
35	    generic (
36	        RstPulseCycles_g    : positive range 3 to positive'high := 3;
37	        RstInPolarity_g     : std_logic                         := '1';
38	        AsyncResetOutput_g  : boolean                           := false;
39	        SyncStages_g        : positive range 2 to 4             := 2
40	    );
41	    port (
42	        Clk         : in    std_logic;
43	        RstOut      : out   std_logic;
44	        RstIn       : in    std_logic := not RstInPolarity_g
45	    );
46	end entity;
47	
48	---------------------------------------------------------------------------------------------------
49	-- Architecture
50	---------------------------------------------------------------------------------------------------
51	architecture struct of olo_base_reset_gen is
52	
53	    -- Reset Synchronizer
54	    signal RstSyncChain : std_logic_vector(2 downto 0)              := "111";
55	    signal RstSync      : std_logic;
56	    signal DsSync       : std_logic_vector(SyncStages_g-1 downto 0) := (others => '1');
57	
58	    -- Pulse prolongation
59	    constant PulseCntMax_c : natural                          := max(RstPulseCycles_g-4, 0);
60	    signal PulseCnt        : integer range 0 to PulseCntMax_c := 0;
61	    signal RstPulse        : std_logic                        := '1';
62	
63	    -- Synthesis attributes - Suppress shift register extraction
64	    attribute shreg_extract of DsSync : signal is ShregExtract_SuppressExtraction_c;
65	    attribute syn_srlstyle of DsSync  : signal is SynSrlstyle_FlipFlops_c;
66	
67	    -- Synthesis attributes - Preserve regsiters
68	    attribute dont_merge of DsSync   : signal is DontMerge_SuppressChanges_c;
69	    attribute preserve of DsSync     : signal is Preserve_SuppressChanges_c;
70	    attribute syn_preserve of DsSync : signal is SynPreserve_SuppressChanges_c;
71	    attribute syn_keep of DsSync     : signal is SynKeep_SuppressChanges_c;
72	
73	    -- Synthesis attributes - asynchronous register
74	    attribute async_reg of DsSync : signal is AsyncReg_TreatAsync_c;
75	
76	begin
77	
78	    -- Reset Synchronizer
79	    p_rstsync : process (RstIn, Clk) is
80	    begin
81	        if RstIn = RstInPolarity_g then
82	            RstSyncChain <= (others => '1');
83	        elsif rising_edge(Clk) then
84	            RstSyncChain <= RstSyncChain(RstSyncChain'left - 1 downto 0) & '0';
85	        end if;
86	    end process;
87	
88	    -- Asynchronous assertion
89	    g_async : if AsyncResetOutput_g generate
90	        RstSync <= RstSyncChain(RstSyncChain'left);
91	    end generate;
92	
93	    -- Synchronous assertion
94	    g_sync : if not AsyncResetOutput_g generate
95	
96	        -- Synchronizer for synchronous assertion
97	        p_sync : process (Clk) is
98	        begin
99	            if rising_edge(Clk) then
100	                DsSync <= DsSync(DsSync'left - 1 downto 0) & RstSyncChain(RstSyncChain'left);
101	            end if;
102	        end process;
103	
104	        RstSync <= DsSync(DsSync'left);
105	    end generate;
106	
107	    -- Prolong reset pulse
108	    g_prolong : if RstPulseCycles_g > 3 generate
109	
110	        -- Generate Pulse
111	        p_prolong : process (Clk) is
112	        begin
113	            if rising_edge(Clk) then
114	                -- Reset
115	                if RstSync = '1' then
116	                    PulseCnt <= 0;
117	                    RstPulse <= '1';
118	                -- Removal
119	                else
120	                    if PulseCnt = PulseCntMax_c then
121	                        RstPulse <= '0';
122	                    else
123	                        PulseCnt <= PulseCnt + 1;
124	                    end if;
125	                end if;
126	            end if;
127	        end process;
128	
129	        -- Asynchronous output
130	        g_async : if AsyncResetOutput_g generate
131	            RstOut <= RstPulse or RstSync;
132	
133	        end generate;
134	
135	        -- Synchronous output
136	        g_sync : if not AsyncResetOutput_g generate
137	            RstOut <= RstPulse;
138	        end generate;
139	
140	    end generate;
141	
142	    g_direct : if RstPulseCycles_g <= 3 generate
143	        RstOut <= RstSync;
144	    end generate;
145	
146	end architecture;
147	
148	
149

