2	-- Copyright (c) 2024 by Oliver Bruendler
3	-- Authors: Oliver Bruendler
4	---------------------------------------------------------------------------------------------------
5	
6	---------------------------------------------------------------------------------------------------
7	-- Description
8	---------------------------------------------------------------------------------------------------
9	-- This entity implements a pipelined first bit decoder. It finds out which
10	-- is the lowest index of a bit set in the input vecotr.
11	--
12	-- Documentation:
13	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_decode_firstbit.md
14	--
15	-- Note: The link points to the documentation of the latest release. If you
16	--       use an older version, the documentation might not match the code.
17	
18	---------------------------------------------------------------------------------------------------
19	-- Libraries
20	---------------------------------------------------------------------------------------------------
21	library ieee;
22	    use ieee.std_logic_1164.all;
23	    use ieee.numeric_std.all;
24	    use ieee.math_real.all;
25	
26	library work;
27	    use work.olo_base_pkg_math.all;
28	    use work.olo_base_pkg_logic.all;
29	    use work.olo_base_pkg_string.all;
30	
31	---------------------------------------------------------------------------------------------------
32	-- Entity Declaration
33	---------------------------------------------------------------------------------------------------
34	entity olo_base_decode_firstbit is
35	    generic (
36	        InWidth_g       : positive;
37	        InReg_g         : boolean := true;
38	        OutReg_g        : boolean := true;
39	        PlRegs_g        : natural := 1
40	    );
41	    port (
42	        -- Clock and Reset
43	        Clk             : in    std_logic;
44	        Rst             : in    std_logic;
45	
46	        -- Input
47	        In_Data         : in    std_logic_vector(InWidth_g-1 downto 0);
48	        In_Valid        : in    std_logic := '1';
49	
50	        -- Output
51	        Out_FirstBit    : out   std_logic_vector(log2ceil(InWidth_g)-1 downto 0);
52	        Out_Found       : out   std_logic;
53	        Out_Valid       : out   std_logic
54	    );
55	end entity;
56	
57	---------------------------------------------------------------------------------------------------
58	-- Architecture Declaration
59	---------------------------------------------------------------------------------------------------
60	architecture rtl of olo_base_decode_firstbit is
61	
62	    -- *** Constants ***
63	    constant EntityName_c     : string  := "olo_base_decode_firstbit";
64	    constant Stages_c         : natural := PlRegs_g+1;
65	    constant BinBits_c        : natural := log2ceil(InWidth_g);
66	    constant InWidthPow2_c    : natural := 2**BinBits_c;
67	    constant AddrBitsStageN_c : natural := BinBits_c/Stages_c;
68	    constant AddrBitsStage1_c : natural := BinBits_c - AddrBitsStageN_c*(Stages_c-1);
69	    constant ParallelStage1_c : natural := InWidthPow2_c/2**AddrBitsStage1_c;
70	
71	    -- *** Types ***
72	    type BinStage_t is array (0 to ParallelStage1_c-1) of std_logic_vector(BinBits_c-1 downto 0);
73	    type BinAll_t is array(0 to Stages_c-1) of BinStage_t;
74	    type Found_t is array(0 to Stages_c-1) of std_logic_vector(ParallelStage1_c-1 downto 0);
75	
76	    -- *** Two Process Method ***
77	    type TwoProcess_r is record
78	        -- Input Registers
79	        DataIn   : std_logic_vector(In_Data'range);
80	        ValidIn  : std_logic;
81	        -- Pipeline Registers
82	        Addr     : BinAll_t;
83	        Found    : Found_t;
84	        Valid    : std_logic_vector(Stages_c-1 downto 0);
85	        -- Output Registers
86	        FirstBit : std_logic_vector(Out_FirstBit'range);
87	        FoundOut : std_logic;
88	        ValidOut : std_logic;
89	    end record;
90	
91	    signal r, r_next : TwoProcess_r;
92	
93	begin
94	
95	    -----------------------------------------------------------------------------------------------
96	    -- Assertions
97	    -----------------------------------------------------------------------------------------------
98	    assert PlRegs_g < BinBits_c/2
99	        report errorMessage(EntityName_c, "PlRegs_g must be smaller than ceil(log2(InWidth_g))/2")
100	        severity error;
101	
102	    -----------------------------------------------------------------------------------------------
103	    -- Combinatorial Process
104	    -----------------------------------------------------------------------------------------------
105	    p_comb : process (all) is
106	        variable v                : TwoProcess_r;
107	        variable DataIn_v         : std_logic_vector(2**BinBits_c-1 downto 0);
108	        variable InValid_v        : std_logic;
109	        variable AddrBits_v       : natural;
110	        variable AddrLowIdx_v     : natural;
111	        variable AddrHighIdx_v    : natural;
112	        variable Parallelism_v    : natural;
113	        variable AddrBitsRemain_v : natural;
114	        variable StartIdx_v       : natural;
115	        variable InBitsPerInst_v  : natural;
116	    begin
117	        -- *** Hold Variables Stble ***
118	        v := r;
119	
120	        -- *** Optional Input Register ***
121	        DataIn_v := (others => '0');
122	        if InReg_g then
123	            v.DataIn                       := In_Data;
124	            v.ValidIn                      := In_Valid;
125	            InValid_v                      := r.ValidIn;
126	            DataIn_v(InWidth_g-1 downto 0) := r.DataIn;
127	        else
128	            DataIn_v(InWidth_g-1 downto 0) := In_Data;
129	            InValid_v                      := In_Valid;
130	        end if;
131	
132	        -- *** Calculate Address ***
133	        AddrLowIdx_v     := 0;
134	        AddrBitsRemain_v := BinBits_c;
135	
136	        -- loop over all stages
137	        for stg in 0 to Stages_c-1 loop
138	            -- Valid handling
139	            if stg = 0 then
140	                v.Valid(stg) := InValid_v;
141	            else
142	                v.Valid(stg) := r.Valid(stg-1);
143	            end if;
144	
145	            -- Calculate Parallelism & Index
146	            if stg = 0 then
147	                AddrBits_v := AddrBitsStage1_c;
148	            else
149	                AddrBits_v := AddrBitsStageN_c;
150	            end if;
151	            AddrHighIdx_v    := AddrLowIdx_v + AddrBits_v - 1;
152	            AddrBitsRemain_v := AddrBitsRemain_v - AddrBits_v;
153	            Parallelism_v    := 2**AddrBitsRemain_v;
154	
155	            -- Calculate Address
156	            InBitsPerInst_v := 2**AddrBits_v;
157	            StartIdx_v      := 0;
158	
159	            -- First stage does only detect the lowerst bit set
160	            if stg = 0 then
161	
162	                -- loop over all parallel instances
163	                for inst in 0 to Parallelism_v-1 loop
164	                    -- First bit detection
165	                    v.Found(0)(inst) := '0';
166	
167	                    -- loop over bits
168	                    for bit in 0 to InBitsPerInst_v-1 loop
169	                        if DataIn_v(StartIdx_v+bit) = '1' then
170	                            v.Addr(0)(inst)  := toUslv(bit, BinBits_c);
171	                            v.Found(0)(inst) := '1';
172	                            exit;
173	                        end if;
174	                    end loop;
175	
176	                    StartIdx_v := StartIdx_v + InBitsPerInst_v;
177	                end loop;
178	
179	            -- All other stages detect lowest found index, select the corresponding address anad extend it
180	            else
181	
182	                -- loop over all parallel instances
183	                for inst in 0 to Parallelism_v-1 loop
184	                    -- First bit detection
185	                    v.Found(stg)(inst) := '0';
186	
187	                    -- loop over bits
188	                    for bit in 0 to InBitsPerInst_v-1 loop
189	                        if r.Found(stg-1)(StartIdx_v+bit) = '1' then
190	                            v.Addr(stg)(inst)                                    := r.Addr(stg-1)(StartIdx_v+bit);
191	                            v.Addr(stg)(inst)(AddrHighIdx_v downto AddrLowIdx_v) := toUslv(bit, AddrBits_v);
192	                            v.Found(stg)(inst)                                   := '1';
193	                            exit;
194	                        end if;
195	                    end loop;
196	
197	                    StartIdx_v := StartIdx_v + InBitsPerInst_v;
198	                end loop;
199	
200	            end if;
201	
202	            -- Increment Addre Index
203	            AddrLowIdx_v := AddrLowIdx_v + AddrBits_v;
204	
205	        end loop;
206	
207	        -- Optional Output Register
208	        v.FoundOut := r.Found(Stages_c-1)(0);
209	        if v.FoundOUt = '1' then
210	            v.FirstBit := r.Addr(Stages_c-1)(0);
211	        else
212	            v.FirstBit := (others => '0'); -- Output zero if not found, simplifies testing in many cases
213	        end if;
214	        v.ValidOut := r.Valid(Stages_c-1);
215	        if OutReg_g then
216	            Out_FirstBit <= r.FirstBit;
217	            Out_Found    <= r.FoundOut;
218	            Out_Valid    <= r.ValidOut;
219	        else
220	            Out_FirstBit <= v.FirstBit;
221	            Out_Found    <= v.FoundOut;
222	            Out_Valid    <= v.ValidOut;
223	        end if;
224	
225	        -- *** Assign to signal ***
226	        r_next <= v;
227	    end process;
228	
229	    -----------------------------------------------------------------------------------------------
230	    -- Sequential Proccess
231	    -----------------------------------------------------------------------------------------------
232	    p_seq : process (Clk) is
233	    begin
234	        if rising_edge(Clk) then
235	            r <= r_next;
236	            if Rst = '1' then
237	                r.ValidIn  <= '0';
238	                r.Valid    <= (others => '0');
239	                r.ValidOut <= '0';
240	            end if;
241	        end if;
242	    end process;
243	
244	end architecture;

